      out.write("		});\r\n");
      out.write("		\r\n");
      out.write("		function close(){\r\n");
      out.write("			if(todayIsDone.checked){\r\n");
      out.write("				//오늘은 더 이상 보지 않는 로직\r\n");
      out.write("				setCookie(popupCookieKey,todayIsDone.checked,1);\r\n");
      out.write("			}\r\n");
      out.write("			popup.classList.remove(\"show\");\r\n");
      out.write("			sessionStorage.setItem(\"popup-close\", \"close\")\r\n");
      out.write("		}\r\n");
      out.write("	\r\n");
      out.write("		function setCookie(key, value, days){\r\n");
      out.write("			var expires = \"\";\r\n");
      out.write("		    if (days) {\r\n");
